SQL> SELECT E.ENAME AS EMPLOYEE_NAME,
  2         E.SAL AS EMP_SALARY,
  3         M.ENAME AS MANAGER_NAME,
  4         M.SAL AS MGR_SALARY,
  5         MM.ENAME AS MANAGER_MANAGER_NAME,
  6         MM.HIREDATE AS MGR_MGR_HIREDATE
  7  FROM EMP E, EMP M, EMP MM
  8  WHERE E.MGR = M.EMPNO
  9    AND M.MGR = MM.EMPNO
 10    AND E.SAL > M.SAL;

