SQL> SELECT E.ENAME AS EMPLOYEE_NAME,
  2         ED.LOC AS EMP_LOCATION,
  3         MM.ENAME AS MGR_MANAGER_NAME,
  4         MD.LOC AS MGR_MGR_LOCATION,
  5         MD.DNAME
  6  FROM EMP E, EMP M, EMP MM, DEPT ED, DEPT MD
  7  WHERE E.MGR = M.EMPNO
  8    AND M.MGR = MM.EMPNO
  9    AND E.DEPTNO = ED.DEPTNO
 10    AND MM.DEPTNO = MD.DEPTNO
 11    AND ED.LOC = MD.LOC;

